/*
* Returns a String for the header subscreen to display the title of the page
*
* by Mateo Rada Arias
*/

return "Cargo Quotation Process";

const list = this.CQP_CLIENT_HISTORY || [];
const len  = list.length;
let output = "";

// 1) Count how many records are selected
let selectedRecords = 0;
for (let i = 0; i < len; i++) {
    if (list[i].SELECTED_RECORD == true) {
        selectedRecords++;
    }
}

// 2) If more than one is selected, append an error banner
if (selectedRecords > 1) {
    output += `You must select only one option.`;
}

// 3) If none is selected also append error banner
if(selectedRecords == 0){
    output += `You must select at least 1 row.`;
}

// 4) Return message (or an empty string if none)
return output;

/*
* Calc Show request error dialog
* by Helen Callisaya
* Modified by Mateo Rada
*/
//validates if the FORTE_ERRORS.FORTE_ERROR_LOG variable has no errors
if (this.FORTE_ERROR.data.FORTE_ERROR_LOG == "" || 
    this.FORTE_ERROR.data.FORTE_ERROR_LOG == "no-error" || 
    this.FORTE_ERROR.data.FORTE_ERROR_LOG == null || 
    this.FORTE_ERROR.data.FORTE_ERROR_LOG == undefined) {
    return false;
} else {
    return true;
}

